if (! function_exists('data_csv_simulator')) {
    function data_csv_simulator($columns, $rows = null, $seed = null)
    {
        $count = min($rows ?? 10, 100);
        if ($seed ?? 0) srand($seed);

        // Helper: seeded random
        if (!function_exists('dcs_rand')) {
            function dcs_rand($min = 0, $max = 1) {
                return $min + (rand() / getrandmax()) * ($max - $min);
            }
        }

        // Random name word list (adjective+noun combos)
        $adjectives = ['Red','Blue','Green','Swift','Calm','Wild','Deep','Bright','Dark','Cool','Warm','Pale','Rich','Soft','Crisp','Dense','Pure','Rough','Smooth','Grand'];
        $nouns = ['River','Mountain','Forest','Cloud','Star','Lake','Stone','Wind','Flame','Ocean','Meadow','Valley','Peak','Dawn','Mist','Tide','Grove','Haven','Shade','Peak'];
        $wordlist = [];
        foreach ($adjectives as $adj) {
            foreach ($nouns as $n) {
                $wordlist[] = $adj . $n;
            }
        }

        $headerNames = [];
        foreach ($columns as $col) {
            $headerNames[] = $col['name'];
        }

        // Generate rows
        $dataRows = [];
        for ($r = 0; $r < $count; $r++) {
            $row = [];
            foreach ($columns as $idx => $col) {
                $pat = $col['pattern'] ?? 'random';
                switch ($pat) {
                    case 'id':
                        $row[] = (string)($r + 1);
                        break;
                    case 'name':
                        $row[] = $wordlist[array_rand($wordlist)];
                        break;
                    case 'int':
                        $mn = (int)($col['min'] ?? 0);
                        $mx = (int)($col['max'] ?? 100);
                        $row[] = (string)rand($mn, $mx);
                        break;
                    case 'random':
                        $mn = (float)($col['min'] ?? 0);
                        $mx = (float)($col['max'] ?? 100);
                        $row[] = number_format(dcs_rand($mn, $mx), 2);
                        break;
                    case 'sine':
                        $amp = (($col['max'] ?? 100) - ($col['min'] ?? 0)) / 2;
                        $mid = ($col['min'] ?? 0) + $amp;
                        $val = $mid + $amp * sin(2 * M_PI * $r / max($count, 1) * ($col['cycles'] ?? 2));
                        $row[] = number_format($val, 2);
                        break;
                    case 'linear':
                        $mn = (float)($col['min'] ?? 0);
                        $mx = (float)($col['max'] ?? 100);
                        $val = $mn + ($mx - $mn) * $r / max($count - 1, 1);
                        $row[] = number_format($val, 2);
                        break;
                    case 'category':
                        $cats = $col['categories'] ?? ['A','B','C'];
                        $row[] = $cats[array_rand($cats)];
                        break;
                    default:
                        $row[] = '?';
                }
            }
            $dataRows[] = $row;
        }

        // Build CSV
        $lines = [implode(',', $headerNames)];
        foreach ($dataRows as $row) {
            $lines[] = implode(',', $row);
        }
        return implode("\n", $lines) . "\n";
    }
